import sqlite3
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]


def test_prefixed_codes_do_not_alias_and_padding_round_trips():
    database = sqlite3.connect(":memory:")
    database.executescript(
        (ROOT / "sql" / "schema.sql").read_text(encoding="utf-8")
    )
    database.executemany(
        "INSERT INTO catalog_items(id, vendor_code, description) VALUES (?, ?, ?)",
        [
            (1, "A-01", "Alpha sensor"),
            (2, "B-02", "Beta sensor"),
            (3, "0009", "Padded switch"),
        ],
    )
    lookup = (ROOT / "sql" / "item_lookup.sql").read_text(
        encoding="utf-8"
    )

    alpha = database.execute(
        lookup, {"vendor_code": "A-01"}
    ).fetchall()
    padded = database.execute(
        lookup, {"vendor_code": "0009"}
    ).fetchall()

    assert alpha == [(1, "A-01", "Alpha sensor")]
    assert padded == [(3, "0009", "Padded switch")]
